pub(crate) fn keyword_or_ident(text: &str) -> TokenKind {
    match text {
        // ... existing matches (lines 222-251) ...
        "inline" => TokenKind::Inline,
        "goto" => TokenKind::Goto,

        // ADD HERE:
        // "restrict" => TokenKind::Restrict,
        // "_Noreturn" => TokenKind::Noreturn,

        _ => TokenKind::Ident(text.to_string()),
    }
